const allowedExtensions = ['xls', 'xlsx', 'pdf', 'zip'];
  const items = $input.all();
  const out = [];                                                                                                   

  for (const item of items) {                                                                                       
    if (!item.binary) {                                  
      out.push({ json: item.json });  // pass through, no binary
      continue;                                                                                                     
    }
    const matches = Object.keys(item.binary).filter(key => {                                                        
      const ext = item.binary[key].fileExtension?.toLowerCase();                                                    
      return ext && allowedExtensions.includes(ext);                                                                
    });                                                                                                             
    if (matches.length === 0) {                                                                                     
      out.push({ json: item.json });  // no allowed attachments
    } else {                                                                                                        
      for (const key of matches) {
        out.push({ json: item.json, binary: { data: item.binary[key] } });                                          
      }                                                  
    }                                                                                                               
  }                                                      

  return out;

const items = $input.all();                                                                                       
  const gmailMsg = $('Get a message').first().json;      

  const emailMetadata = {                                                                                           
    email_id: gmailMsg.id,
    from: gmailMsg.from?.value?.[0]?.address || '',                                                                 
    conversation_id: gmailMsg.threadId,                  
    subject: gmailMsg.subject || '',                                                                                
    body: gmailMsg.text || '',
    date: gmailMsg.date || '',                                                                                      
  };                                                     

  const attachments = [];

  for (let i = 0; i < items.length; i++) {                                                                          
    const item = items[i];
    if (!item.binary?.data) continue;                                                                               
    const fileName = item.binary.data.fileName || `attachment_${i}`;
    const mimeType = item.binary.data.mimeType || 'application/pdf';                                                
    try {
      const buf = await this.helpers.getBinaryDataBuffer(i, 'data');                                                
      attachments.push({                                                                                            
        file_data: buf.toString('base64'),
        file_name: fileName,                                                                                        
        mime_type: mimeType,                             
      });
    } catch (e) {
      console.error(`Failed ${fileName}: ${e.message}`);
    }                                                                                                               
  }

  // Build ADK parts array — text always; inlineData only if attachments exist                                      
  const parts = [
    {                                                                                                               
      text:                                              
        `From: ${emailMetadata.from}\n` +
        `Subject: ${emailMetadata.subject}\n` +                                                                     
        `Email-ID: ${emailMetadata.email_id}\n` +
        `Date: ${emailMetadata.date}\n\n` +                                                                         
        emailMetadata.body,                                                                                         
    },
    ...attachments.map(a => ({                                                                                      
      inlineData: {                                      
        displayName: a.file_name,
        mimeType: a.mime_type,                                                                                      
        data: a.file_data,
      },                                                                                                            
    })),                                                 
  ];

  return [{ json: { attachments, email_metadata: emailMetadata, parts } }];
